import { Box, Checkbox, FormControlLabel, FormGroup, Modal, Typography } from '@mui/material';
import React from 'react';
import { Genre } from '../../types/movies-grid.types';
import { useUserPreferences } from '../../context/user-preferences';

const mockGenres: Array<Genre> = [
	{
		id: 28,
		name: 'Action'
	},
	{
		id: 12,
		name: 'Adventure'
	},
	{
		id: 16,
		name: 'Animation'
	},
	{
		id: 35,
		name: 'Comedy'
	},
	{
		id: 80,
		name: 'Crime'
	},
	{
		id: 99,
		name: 'Documentary'
	},
	{
		id: 18,
		name: 'Drama'
	},
	{
		id: 10751,
		name: 'Family'
	},
	{
		id: 14,
		name: 'Fantasy'
	},
	{
		id: 36,
		name: 'History'
	},
	{
		id: 27,
		name: 'Horror'
	},
	{
		id: 10402,
		name: 'Music'
	},
	{
		id: 9648,
		name: 'Mystery'
	},
	{
		id: 10749,
		name: 'Romance'
	},
	{
		id: 878,
		name: 'Science Fiction'
	},
	{
		id: 10770,
		name: 'TV Movie'
	},
	{
		id: 53,
		name: 'Thriller'
	},
	{
		id: 10752,
		name: 'War'
	},
	{
		id: 37,
		name: 'Western'
	}
];

const style = {
	position: 'absolute' as const,
	top: '50%',
	left: '50%',
	transform: 'translate(-50%, -50%)',
	width: 800,
	height: 600,
	bgcolor: 'background.paper',
	border: '2px solid #000',
	boxShadow: 24,
	p: 4
};

const selectedGenresArray: Array<any> = [];

function handleGenreSelection(checked: boolean, selectedGenre: Genre, setGenres: any, genres: any, contextKey: number, setContextKey: any) {
	// commentary: reduce amount of parameters
	if (checked === true) {
		selectedGenresArray.push(selectedGenre);
	}
	if (checked === false) {
		const index = selectedGenresArray.indexOf(selectedGenre);
		selectedGenresArray.splice(index, 1);
	}

	return selectedGenresArray;
}

export default function StartModal() {
	const [open, setOpen] = React.useState(true);
	const { genres, setGenres, setContextKey, contextKey } = useUserPreferences();
	const handleClose = () => setOpen(false);

	return (
		<div>
			<Modal open={open} onClose={handleClose} aria-labelledby="modal-modal-title" aria-describedby="modal-modal-description">
				<Box sx={style}>
					<Typography id="modal-modal-title" variant="h6" component="h2">
						Selecione suas preferências
					</Typography>
					<Typography id="modal-modal-description" sx={{ mt: 2 }}>
						Selecione no mínimo 3 e no máximo 5 opções de Gênero.
						<FormGroup>
							<div className="justify-center grid grid-cols-3 p-6">
								{mockGenres.map((mockGenre, index) => {
									return (
										<FormControlLabel
											control={<Checkbox onClick={e => handleGenreSelection((e.target as HTMLInputElement).checked, mockGenre, setGenres, genres, contextKey, setContextKey)} />}
											label={`${mockGenre.name}`}
											key={`check ${index}`}
										/>
									);
								})}
							</div>
						</FormGroup>
					</Typography>
				</Box>
			</Modal>
		</div>
	);
}
